INSERT INTO questions (
  id, package_id, round_no, board_row, board_col, points, prompt, answer_display, answer_time_limit_ms
)
VALUES
  ('77777777-7777-7777-7777-000000200001', '77777777-7777-7777-7777-000000001001', 1, 1, 1, 100, 'Каждому цветку богиня Флора дала имя, но лишь один остался безымянным. И тогда богиня подарила ему чудесную силу – это возможность возвращать каждому человеку память. Назовите этот цветок', 'незабудка', 5000),
  ('77777777-7777-7777-7777-000000200002', '77777777-7777-7777-7777-000000001001', 1, 1, 2, 200, 'Именно ЭТОТ цветок съел Козёл в гостях у Кошки в произведении Маршака «Кошкин дом»', 'Герань', 5000),
  ('77777777-7777-7777-7777-000000200003', '77777777-7777-7777-7777-000000001001', 1, 1, 3, 300, 'ЭТОТ цветок растёт среди ржи, уничтожая посевы культуры, поэтому считается злым врагом для всех хлеборобов. Назовите этот цветок словом-рифмой к гибели богов и всего мира в скандинавской мифологии', 'Василёк', 5000),
  ('77777777-7777-7777-7777-000000200004', '77777777-7777-7777-7777-000000001001', 1, 1, 4, 400, 'В переводе с греческого языка название ЭТОГО цветка означает «жемчужина»', 'маргаритка', 5000),
  ('77777777-7777-7777-7777-000000200005', '77777777-7777-7777-7777-000000001001', 1, 1, 5, 500, 'Назовите фамилию английского врача и натуралиста, в честь которого получил название самый крупный в мире цветок, обитающий в тропических лесах на острове Суматра и достигающий в диаметре 91 см и массу 11 кг', 'Арнольд', 5000),
  ('77777777-7777-7777-7777-000000200006', '77777777-7777-7777-7777-000000001001', 1, 2, 1, 100, 'Самый низкий из НИХ - Авентин, самый высокий – Квиринал', 'Римские холмы', 5000),
  ('77777777-7777-7777-7777-000000200007', '77777777-7777-7777-7777-000000001001', 1, 2, 2, 200, 'Большую часть своих голов в Серии А её лучший на данный момент бомбардир Сильвио Пиола забил, выступая за ЭТОТ римский футбольный клуб', 'Лацио', 5000),
  ('77777777-7777-7777-7777-000000200008', '77777777-7777-7777-7777-000000001001', 1, 2, 3, 300, 'ЭТОТ фонтан Рима включает аллегорические фигуры Нила, Ганга, Дуная и Ла-Платы', 'Фонтан четырёх рек', 5000),
  ('77777777-7777-7777-7777-000000200009', '77777777-7777-7777-7777-000000001001', 1, 2, 4, 400, 'Из шести Великих папских базилик четыре расположены в Риме, а две других в ЭТОМ городке - родине учредителя ордена францисканцев', 'Ассизи', 5000),
  ('77777777-7777-7777-7777-000000200010', '77777777-7777-7777-7777-000000001001', 1, 2, 5, 500, 'ЭТОТ советский актёр и режиссёр исполнил роль сержанта Фёдора Назукова в фильме Роберто Росселлини «В Риме была ночь»', 'Сергей Бондарчук', 5000),
  ('77777777-7777-7777-7777-000000200011', '77777777-7777-7777-7777-000000001001', 1, 3, 1, 100, 'Автор ЭТОЙ киевской скульптуры - Олег Дергачёв. Привлекает толпы людей: каждый третий прохожий его утирает', 'нос Гоголя', 5000),
  ('77777777-7777-7777-7777-000000200012', '77777777-7777-7777-7777-000000001001', 1, 3, 2, 200, 'ЭТА бывшая солистка группы «ВИА Гра» продолжает творческую деятельность под своей настоящей фамилией – Мейхер', 'Надежда Грановская', 5000),
  ('77777777-7777-7777-7777-000000200013', '77777777-7777-7777-7777-000000001001', 1, 3, 3, 300, 'К НЕЙ, кроме всего прочего, относятся: владение понятием эксперимента и логического вывода, умение описывать, объяснять и прогнозировать природные явления, способность оценивать качество обнаруженной информации исходя из источников и методов получения', 'научная грамотность', 5000),
  ('77777777-7777-7777-7777-000000200014', '77777777-7777-7777-7777-000000001001', 1, 3, 4, 400, 'Представьте, как на полу валяется ваш телефон. К нему подключена зарядка, которая вставлена в ЭТО. При этом вы подтанцовываете, а телефон заряжается', 'ножной генератор', 5000),
  ('77777777-7777-7777-7777-000000200015', '77777777-7777-7777-7777-000000001001', 1, 3, 5, 500, 'До обретения Южным Суданом независимости в 2011 году ОНИ образовывали центр Судана', 'Нубийские горы', 5000),
  ('77777777-7777-7777-7777-000000200016', '77777777-7777-7777-7777-000000001001', 1, 4, 1, 100, 'Клип Фёдора Бондарчука на ЕЁ песню «Посмотри в глаза» получил главный приз на первом российском фестивале кино-видеоклипов Generation-92', 'Наталья ВЕТлицкая', 5000),
  ('77777777-7777-7777-7777-000000200017', '77777777-7777-7777-7777-000000001001', 1, 4, 2, 200, 'В повседневный рацион красных ибисов входят ОНИ, обеспечивающие птицам соответствующую окраску', 'креВЕТки', 5000),
  ('77777777-7777-7777-7777-000000200018', '77777777-7777-7777-7777-000000001001', 1, 4, 3, 300, 'Чтобы придать ЕЙ уникальный вкус, производители из города Смитфилд (штат Виргиния) кормят местных поросят отборным арахисом', 'ВЕТчина', 5000),
  ('77777777-7777-7777-7777-000000200019', '77777777-7777-7777-7777-000000001001', 1, 4, 4, 400, 'У пиона ОНО плоское, у лютика — коническое, а у розы — вогнутое', 'цВЕТоложе', 5000),
  ('77777777-7777-7777-7777-000000200020', '77777777-7777-7777-7777-000000001001', 1, 4, 5, 500, 'ЭТА фотометрическая величина пропорциональна квадрату относительного отверстия оптической системы', 'сВЕТосила', 5000),
  ('77777777-7777-7777-7777-000000200021', '77777777-7777-7777-7777-000000001002', 1, 1, 1, 100, 'Наутхолсвик — единственный пляж в Исландии, где официально разрешено ДЕЛАТЬ ЭТО', 'купаться', 5000),
  ('77777777-7777-7777-7777-000000200022', '77777777-7777-7777-7777-000000001002', 1, 1, 2, 200, 'Около 10% площади Исландии занимает Ватнайёкюдль — самый крупный ОН в Европе', 'ледник', 5000),
  ('77777777-7777-7777-7777-000000200023', '77777777-7777-7777-7777-000000001002', 1, 1, 3, 300, 'Российское ОНО обрело название в 1967 году. В Исландии ОНО тоже есть, проходящее по маршруту: Рейкьявик – Кверагерди – Долина гейзеров – водопад Гульфосс – Тингветлир – Рейкьявик', 'Золотое кольцо', 5000),
  ('77777777-7777-7777-7777-000000200024', '77777777-7777-7777-7777-000000001002', 1, 1, 4, 400, 'Среди исландцев и туристов популярен Геотаун. Таун — понятно, городок, а «гео» — сокращение именно ЭТОГО прилагательного', 'геотермальный', 5000),
  ('77777777-7777-7777-7777-000000200025', '77777777-7777-7777-7777-000000001002', 1, 1, 5, 500, 'Название эпизода телепрограммы «Орел и решка» об Исландии совпало с ЭТИМ заголовком одной из частей кинофраншизы о пиратах Карибского моря', 'На краю света', 5000),
  ('77777777-7777-7777-7777-000000200026', '77777777-7777-7777-7777-000000001002', 1, 2, 1, 100, 'Снофру, первый фараон Четвертой династии, построил четыре пирамиды в Медуме и Дахшуре. А его известного сына звали именно ТАК', 'Хеопс', 5000),
  ('77777777-7777-7777-7777-000000200027', '77777777-7777-7777-7777-000000001002', 1, 2, 2, 200, 'Одна из отличительных черт статуй с изображением фараона Сенусерта III - большие ОНИ. Возможно, дело в физиологии, но, вероятнее всего, он учитывал все пожелания собственного народа', 'уши', 5000),
  ('77777777-7777-7777-7777-000000200028', '77777777-7777-7777-7777-000000001002', 1, 2, 3, 300, 'Слова «любить»и «любовь» в Древнем Египте изображались иероглифом в виде НЕЁ. Собственно, любовь и нужно тщательно возделывать, чтобы она расцветала пышным цветом', 'мотыга', 5000),
  ('77777777-7777-7777-7777-000000200029', '77777777-7777-7777-7777-000000001002', 1, 2, 4, 400, 'В древнеегипетском городе Иуну был сильно развит культ бога солнца Ра. Назовите греческое название этого города', 'Гелиополь', 5000),
  ('77777777-7777-7777-7777-000000200030', '77777777-7777-7777-7777-000000001002', 1, 2, 5, 500, 'ЭТИМ словом египтологи называют тип гробниц, принадлежавших приближенным фараонов. А вообще ОНА обозначает скамейку, которую можно встретить у входа египетских деревенских домов и сегодня', 'мастаба', 5000),
  ('77777777-7777-7777-7777-000000200031', '77777777-7777-7777-7777-000000001002', 1, 3, 1, 100, 'Кампучия', 'Камбоджа', 5000),
  ('77777777-7777-7777-7777-000000200032', '77777777-7777-7777-7777-000000001002', 1, 3, 2, 200, 'Сиам', 'Таиланд', 5000),
  ('77777777-7777-7777-7777-000000200033', '77777777-7777-7777-7777-000000001002', 1, 3, 3, 300, 'Нидерландская Гвиана', 'Суринам', 5000),
  ('77777777-7777-7777-7777-000000200034', '77777777-7777-7777-7777-000000001002', 1, 3, 4, 400, 'Эспаньола', 'Гаити', 5000),
  ('77777777-7777-7777-7777-000000200035', '77777777-7777-7777-7777-000000001002', 1, 3, 5, 500, 'Ньясаленд', 'Малави', 5000),
  ('77777777-7777-7777-7777-000000200036', '77777777-7777-7777-7777-000000001002', 1, 4, 1, 100, '«Неча на зеркало пенять, коли рожа крива»', 'Ревизор', 5000),
  ('77777777-7777-7777-7777-000000200037', '77777777-7777-7777-7777-000000001002', 1, 4, 2, 200, '«...Так кто ж ты, наконец? – Я – часть той силы, что вечно хочет зла и вечно совершает благо».', 'Мастер и Маргарита', 5000),
  ('77777777-7777-7777-7777-000000200038', '77777777-7777-7777-7777-000000001002', 1, 4, 3, 300, '«Юристы тоже, наверное, когда-то были детьми»', 'Убить пересмешника', 5000),
  ('77777777-7777-7777-7777-000000200039', '77777777-7777-7777-7777-000000001002', 1, 4, 4, 400, '«Нет человека, который был бы как Остров, сам по себе, каждый человек есть часть Материка, часть Суши; и если волной снесёт в море береговой Утёс, меньше станет Европа, и так же, если смоет край мыса или разрушит Замок твой или друга твоего;...»', 'По ком звонит колокол', 5000),
  ('77777777-7777-7777-7777-000000200040', '77777777-7777-7777-7777-000000001002', 1, 4, 5, 500, '«Истинно, истинно говорю вам: если зерно, падши в землю, не умрёт, то останется одно, а если умрёт, то принесёт много плода»', 'Братья Карамазовы', 5000),
  ('77777777-7777-7777-7777-000000200041', '77777777-7777-7777-7777-000000001003', 1, 1, 1, 100, 'Психология юмора была подробно описана ЭТИМ австрийцем в работе «Остроумие и его отношение к бессознательному»', 'Зигмунд Фрейд', 5000),
  ('77777777-7777-7777-7777-000000200042', '77777777-7777-7777-7777-000000001003', 1, 1, 2, 200, 'Так как большая часть звуков для дорожек с закадровым смехом была записана в 1950-х годах, на американском телевидении популярна шутка о том, что над современными ситкомами смеются в основном ОНИ', 'покойники', 5000),
  ('77777777-7777-7777-7777-000000200043', '77777777-7777-7777-7777-000000001003', 1, 1, 3, 300, 'В списке ста величайших ИХ всех времён, составленным в 2004 году американским телеканалом Comedy Central, первое место занял Ричард Прайор, второе — Джордж Карлин, третье — Ленни Брюс', 'стендап-комики (стендаперы)', 5000),
  ('77777777-7777-7777-7777-000000200044', '77777777-7777-7777-7777-000000001003', 1, 1, 4, 400, 'Классическая шутка состоит из двух частей: вводной ситуации или сетапа (setup) и ударной остроумной концовки, которая называется именно ТАК. Ответьте словом, в котором все гласные одинаковые', 'панчлайн (панч)', 5000),
  ('77777777-7777-7777-7777-000000200045', '77777777-7777-7777-7777-000000001003', 1, 1, 5, 500, 'ЭТОТ американский комик на протяжении 23 лет был ведущим популярного ток-шоу на канале CBS, ставшего, например, прообразом российского «Вечернего Урганта»', 'Дэвид Леттерман', 5000),
  ('77777777-7777-7777-7777-000000200046', '77777777-7777-7777-7777-000000001003', 1, 2, 1, 100, 'Название ЭТОГО устройства происходит от английского акронима, означающего «усиление света посредством вынужденного излучения»', 'лазер', 5000),
  ('77777777-7777-7777-7777-000000200047', '77777777-7777-7777-7777-000000001003', 1, 2, 2, 200, 'Изначально на аверсе ЭТОЙ венецианской монеты был изображён коленопреклонённый перед апостолом Марк, а на реверсе - Христос. Венецианского льва поместили на аверс лишь век спустя', 'газетта', 5000),
  ('77777777-7777-7777-7777-000000200048', '77777777-7777-7777-7777-000000001003', 1, 2, 3, 300, 'Дочь ЭТОГО канадского актёра, Сара Джуд, родилась в один день с его падчерицей Мишель Кэт, дочерью его первой супруги Камелии', 'Кифер Сазерленд', 5000),
  ('77777777-7777-7777-7777-000000200049', '77777777-7777-7777-7777-000000001003', 1, 2, 4, 400, 'ЭТОТ уроженец Гродненской губернии стал прототипом провокатора Липпанченки, персонажа романа «Петербург» Андрея Белого. А вот Саша Чёрный посвятил ему стихотворение «Герой нашего времени»', 'Евно Азеф', 5000),
  ('77777777-7777-7777-7777-000000200050', '77777777-7777-7777-7777-000000001003', 1, 2, 5, 500, 'ЭТОТ немецкий врач прославился своим исследованием так называемой «мерзебургской триады», в которую входят сердцебиение, зоб и пучеглазие', 'Базедов', 5000),
  ('77777777-7777-7777-7777-000000200051', '77777777-7777-7777-7777-000000001003', 1, 3, 1, 100, 'Таков результат сложения двух первых простых чисел', '5 (2+3)', 5000),
  ('77777777-7777-7777-7777-000000200052', '77777777-7777-7777-7777-000000001003', 1, 3, 2, 200, 'Тeрритории СТОЛЬKИX южноaмeрикaнских стрaн пeрeсeкaются экватором', '3 (Эквадор, Колумбия, Бразилия)', 5000),
  ('77777777-7777-7777-7777-000000200053', '77777777-7777-7777-7777-000000001003', 1, 3, 3, 300, 'В 1995 году влаcти Tайбэя издали закон, официально pазpешающий жителям удалять ЭTO чиcло из топогpафичеcкиx названий', '4', 5000),
  ('77777777-7777-7777-7777-000000200054', '77777777-7777-7777-7777-000000001003', 1, 3, 4, 400, 'Летом 2016 гoдачислo белорусских «миллиoнерoв»резкo сoкратилoсь. Bинoй тoмy — денoминация нацвалюты, пo итoгам кoтoрoй с местных кyпюр исчезло CТOЛЬKO нулей', '4', 5000),
  ('77777777-7777-7777-7777-000000200055', '77777777-7777-7777-7777-000000001003', 1, 3, 5, 500, 'Джакомо да Виньoлa известен не тoлькo кaк apхитектop пoзднегo Вoзpoждения, нo и кaк теopетик, выделивший ТАKOE кoличествo клaссических apхитектypных opдеpoв', '5 (дорический, ионический, коринфский, тосканский и композитный)', 5000),
  ('77777777-7777-7777-7777-000000200056', '77777777-7777-7777-7777-000000001003', 1, 4, 1, 100, 'Польская актриса Беата Тышкевич снялась в трёх фильмах ЭТОГО режиссёра: «Самсон», «Пепел» и «Всё на продажу». И пять лет была его женой', 'Анджей Вайда', 5000),
  ('77777777-7777-7777-7777-000000200057', '77777777-7777-7777-7777-000000001003', 1, 4, 2, 200, 'Согласно энциклопедии Брокгауза и Ефрона, ЕЁ «устроил» голландский физик Мушенбрук, а удар от разряда испытал гражданин Кюнеус', 'Лейденская банка', 5000),
  ('77777777-7777-7777-7777-000000200058', '77777777-7777-7777-7777-000000001003', 1, 4, 3, 300, 'С детства ОН страдал заиканием: ЕМУ тяжело давались слова, начинающиеся на букву s. Желая побороть дефект, ОН становился с фонариком, поднесённым к лицу, напротив зеркала, цитируя Йейтса, Эмерсона и цитаты из Декларации независимости', 'Джо Байден', 5000),
  ('77777777-7777-7777-7777-000000200059', '77777777-7777-7777-7777-000000001003', 1, 4, 4, 400, 'Главная ЕГО достопримечательность - озеро Серпентайн. А в 2004 году там открыли монумент, посвященный памяти животных, участвовавших в войнах', 'Гайд-парк', 5000),
  ('77777777-7777-7777-7777-000000200060', '77777777-7777-7777-7777-000000001003', 1, 4, 5, 500, 'Одним из прототипов Робина Гуда был средневековый пират Клаус Штёртебекер. Своё прозвище, по легенде, он получил в честь ЭТОГО призыва', 'Пей до дна', 5000),
  ('77777777-7777-7777-7777-000000200061', '77777777-7777-7777-7777-000000001004', 1, 1, 1, 100, 'В четвёрку имперских городов ЭТОЙ страны, помимо столичного, входят Фес, Марракеш и Мекнес', 'Марокко', 5000),
  ('77777777-7777-7777-7777-000000200062', '77777777-7777-7777-7777-000000001004', 1, 1, 2, 200, 'Действие романа Жюля Верна «Приключения трёх русских и трёх англичан в Южной Африке» начинается на берегу ЭТОЙ «цветной» реки', 'Оранжевая', 5000),
  ('77777777-7777-7777-7777-000000200063', '77777777-7777-7777-7777-000000001004', 1, 1, 3, 300, 'В XXI веке ЭТУ организацию пополнили четыре африканских государства: Габон, Ангола, Экваториальная Гвинея и Республика Конго. Что это за межправительственный картель?', 'ОПЕК', 5000),
  ('77777777-7777-7777-7777-000000200064', '77777777-7777-7777-7777-000000001004', 1, 1, 4, 400, 'Из 55 африканских стран 16 не имеют ЭТОГО. Например, Эфиопия, утратившая ЭТО в 1993 году', 'выход к морю', 5000),
  ('77777777-7777-7777-7777-000000200065', '77777777-7777-7777-7777-000000001004', 1, 1, 5, 500, 'Ботсвана имеет общие границы на юге и юго-востоке с ЮАР, на севере и западе - с Намибией. Назовите две страны, с которыми Ботсвана граничит на северо-востоке', 'Замбия и Зимбабве', 5000),
  ('77777777-7777-7777-7777-000000200066', '77777777-7777-7777-7777-000000001004', 1, 2, 1, 100, 'В 2017 году Дэвиду Брэдли понадобилось 20 килограммов чеддера, чтобы изваять скульптуру ЭТОЙ популярной певицы. Своё творение мастер назвал Brie-oncé', 'Бейонсе', 5000),
  ('77777777-7777-7777-7777-000000200067', '77777777-7777-7777-7777-000000001004', 1, 2, 2, 200, 'С 2013 года по маршруту Монтрё – Шато д''Э – Монтрё курсирует экскурсионный «Сырный поезд», на котором путешественники смогут отведать в том числе и ЭТО приготовленное на открытом огне традиционное блюдо', 'фондю', 5000),
  ('77777777-7777-7777-7777-000000200068', '77777777-7777-7777-7777-000000001004', 1, 2, 3, 300, 'На обёртке сыра Вьё-Лилль нередко изображают человека в НЁМ', 'противогаз', 5000),
  ('77777777-7777-7777-7777-000000200069', '77777777-7777-7777-7777-000000001004', 1, 2, 4, 400, 'Швейцарский Тет де Муан следует соскабливать специальным ножом для круговой нарезки. Головка сыра после такой «процедуры» становится похожа на голову именно ЕГО после проведения над НИМ символического обрядового действия', 'монах', 5000),
  ('77777777-7777-7777-7777-000000200070', '77777777-7777-7777-7777-000000001004', 1, 2, 5, 500, 'ЭТОТ азербайджанский мягкий рассольный сыр в 2011 году попал в список «Ковчег вкуса» как аутентичный пищевой продукт, находящийся на грани исчезновения', 'мотал', 5000),
  ('77777777-7777-7777-7777-000000200071', '77777777-7777-7777-7777-000000001004', 1, 3, 1, 100, 'Первой женой ЭТОГО российского монарха была Анастасия Романовна, урождённая Захарьина-Юрьева', 'Иоанн Грозный', 5000),
  ('77777777-7777-7777-7777-000000200072', '77777777-7777-7777-7777-000000001004', 1, 3, 2, 200, 'ЭТОТ музыкальный коллектив в 1970-х годах стал первым в череде самых громких групп мира в Книге рекордов Гиннесса. Что это за рок-группа с хитами Smoke on the Water, Hush, Lalena и Lazy?', 'Deep Purple', 5000),
  ('77777777-7777-7777-7777-000000200073', '77777777-7777-7777-7777-000000001004', 1, 3, 3, 300, 'Первое напечатанное стихотворение Александра Пушкина «К другу стихотворцу» было обращено к ЭТОМУ лицейскому товарищу юного поэта', 'Вильгельм Кюхельбекер', 5000),
  ('77777777-7777-7777-7777-000000200074', '77777777-7777-7777-7777-000000001004', 1, 3, 4, 400, 'Первым в истории YouTube видеоклипом, набравшим 10 миллиардов просмотров, стала южнокорейская детская песенка, в которой многократно упоминалась ЭТА рыба', 'акула (Baby Shark)', 5000),
  ('77777777-7777-7777-7777-000000200075', '77777777-7777-7777-7777-000000001004', 1, 3, 5, 500, 'Первым председателем «Детективного клуба» (Detection Club), созданного в Лондоне в 1930-х годах, стал не Артур Конан Дойл и не Агата Кристи, а ЭТОТ английский писатель и философ', 'Гилберт Кит Честертон', 5000),
  ('77777777-7777-7777-7777-000000200076', '77777777-7777-7777-7777-000000001004', 1, 4, 1, 100, 'Заряженные ОНИ, известные также как «пи-мезоны», распадаются на нейтрино и мюоны, в то время как нейтральные ОНИ распадаются на фотоны. Других ИХ вы можете встретить либо в саду, либо на страницах учебников ботаники', 'пионы', 5000),
  ('77777777-7777-7777-7777-000000200077', '77777777-7777-7777-7777-000000001004', 1, 4, 2, 200, 'В ЕГО физических экспериментах середины XIX века были определены значения для скорости света. Более всего ОН прославился благодаря маятнику, а Умберто Эко даже поместил ЕГО в заголовок своего произведения', 'Фуко', 5000),
  ('77777777-7777-7777-7777-000000200078', '77777777-7777-7777-7777-000000001004', 1, 4, 3, 300, '«Чем лучше вы будете знать положение квантовой частицы, тем менее точно вы будете знать её импульс, и наоборот», - так формулируется ЭТОТ принцип в физике, названный по имени Вернера Гейзенберга', 'принцип неопределенности', 5000),
  ('77777777-7777-7777-7777-000000200079', '77777777-7777-7777-7777-000000001004', 1, 4, 4, 400, 'Во время Крымской войны ЕГО попросили проанализировать применение отравляющего газа в качестве оружия, но по этическим причинам ОН отказался. Зато несколькими годами ранее два закона электролиза сформулировал', 'Майкл Фарадей', 5000),
  ('77777777-7777-7777-7777-000000200080', '77777777-7777-7777-7777-000000001004', 1, 4, 5, 500, 'Античастицей электронаявляется позитрон. Назовите античастицу протона', 'антипротон', 5000),
  ('77777777-7777-7777-7777-000000200081', '77777777-7777-7777-7777-000000001005', 1, 1, 1, 100, 'Именно ЭТО находится в «ногах» Ориона', 'Созвездие Заяц', 5000),
  ('77777777-7777-7777-7777-000000200082', '77777777-7777-7777-7777-000000001005', 1, 1, 2, 200, 'Именно с ЭТОЙ крепости на Заячьем острове началось строительство Санкт-Петербурга', 'Петропавловская крепость', 5000),
  ('77777777-7777-7777-7777-000000200083', '77777777-7777-7777-7777-000000001005', 1, 1, 3, 300, 'Только не отвечайте «грызуны». К какому отряду млекопитающих относятся зайцы?', 'зайцеобразные', 5000),
  ('77777777-7777-7777-7777-000000200084', '77777777-7777-7777-7777-000000001005', 1, 1, 4, 400, 'Завершите загадку Александра Измайлова рифмованным словом: Скачет мальчик по дорожкам, По просёлочным Он без ушек, он без ножек, Зайчик… какой?', 'солнечный', 5000),
  ('77777777-7777-7777-7777-000000200085', '77777777-7777-7777-7777-000000001005', 1, 1, 5, 500, 'На Безумном чаепитии присутствовали Сурок, Безумный шляпник и ОН. Ответьте двумя словами', 'Мартовский Заяц', 5000),
  ('77777777-7777-7777-7777-000000200086', '77777777-7777-7777-7777-000000001005', 1, 2, 1, 100, 'ЭТОТ праздник отмечается через 70 дней после праздника Ураза-байрам и в десятый день месяца Зуль-хиджа в память жертвоприношения пророка Ибрагима', 'Курбан-байрам', 5000),
  ('77777777-7777-7777-7777-000000200087', '77777777-7777-7777-7777-000000001005', 1, 2, 2, 200, 'Одна из дочерей ЭТОГО короля Германии была помолвлена с будущим королём Англии Ричардом Львиное Сердце. Историки полагают, что ею была Гизелла', 'Фридрих Барбаросса', 5000),
  ('77777777-7777-7777-7777-000000200088', '77777777-7777-7777-7777-000000001005', 1, 2, 3, 300, 'С 30 ноября 2021 года ОН стал республикой, перестав подчиняться Елизавете Второй. В тот же день национальным героем республики стала певица Рианна', 'Барбадос', 5000),
  ('77777777-7777-7777-7777-000000200089', '77777777-7777-7777-7777-000000001005', 1, 2, 4, 400, 'ЭТОТ словацкий теннисист и экс-двенадцатая ракетка планеты в теннисном мире был обладателем прозвища «Доминатор»', 'Доминик Хрбаты', 5000),
  ('77777777-7777-7777-7777-000000200090', '77777777-7777-7777-7777-000000001005', 1, 2, 5, 500, 'За роль мадам Гортензии в ЭТОМ фильме Михалиса Какоянниса Лия Кедрова удостоилась «Оскара» за лучшую женскую роль второго плана. А Уолтер Лассали - за лучшую операторскую работу', 'Грек Зорба', 5000),
  ('77777777-7777-7777-7777-000000200091', '77777777-7777-7777-7777-000000001005', 1, 3, 1, 100, 'Векторная диаграмма, характеризующая режим воздушных потоков в данном месте по многолетним наблюдениям, называется именно ТАК', 'Роза ветров', 5000),
  ('77777777-7777-7777-7777-000000200092', '77777777-7777-7777-7777-000000001005', 1, 3, 2, 200, 'Именно ТАК в древнегреческой мифологии звали прекрасного юношу, которого погубила любовь к самому себе', 'Нарцисс', 5000),
  ('77777777-7777-7777-7777-000000200093', '77777777-7777-7777-7777-000000001005', 1, 3, 3, 300, 'Назовите автомобиль С-класса, отвечающий нашей теме, производимый компанией Опель с 1991 года', 'Астра', 5000),
  ('77777777-7777-7777-7777-000000200094', '77777777-7777-7777-7777-000000001005', 1, 3, 4, 400, 'ЭТОТ ударный музыкальный инструмент, который иногда можно встретить в симфоническом оркестре, на немецкий манер называют глюкеншпилем', 'колокольчики', 5000),
  ('77777777-7777-7777-7777-000000200095', '77777777-7777-7777-7777-000000001005', 1, 3, 5, 500, 'Старшую дочь Эластики и Мистера Исключительность из «Суперсемейки» зовут именно ТАК', 'Фиалка', 5000),
  ('77777777-7777-7777-7777-000000200096', '77777777-7777-7777-7777-000000001005', 1, 4, 1, 100, 'Сначала была удивительная находка, затем покупка. Потом ОНА чуть не лишилась жизни, но чудесное спасение привело к свадьбе со спасителем. И всё это в ЕЁ День рождения! Назовите ЕЁ', 'Муха-Цокотуха', 5000),
  ('77777777-7777-7777-7777-000000200097', '77777777-7777-7777-7777-000000001005', 1, 4, 2, 200, 'На просторах Интернета бытует шутка, что «По законам физики ОН летать не должен, но ОН об этом не знает и всё равно летает». Назовите его, переведя с латыни слово Bombus', 'Шмель', 5000),
  ('77777777-7777-7777-7777-000000200098', '77777777-7777-7777-7777-000000001005', 1, 4, 3, 300, 'Один из почитаемых символов Древнего Египта, ОН своим движением с шариком навоза с востока на запад символизировал рождение и движение Солнца на небосводе. Кто ОН?', 'Жук Скарабей', 5000),
  ('77777777-7777-7777-7777-000000200099', '77777777-7777-7777-7777-000000001005', 1, 4, 4, 400, 'Рабочие - единственная каста термитов, способная переваривать именно ЭТОТ полисахарид благодаря особым кишечным микроорганизмам-симбионтам', 'целлюлоза', 5000),
  ('77777777-7777-7777-7777-000000200100', '77777777-7777-7777-7777-000000001005', 1, 4, 5, 500, 'Самка именно ЭТОГО насекомого по имени Надежда не только побывала в космосе, но и оставила зачатое во время космического полёта потомство', 'Таракан', 5000),
  ('77777777-7777-7777-7777-000000200101', '77777777-7777-7777-7777-000000001006', 1, 1, 1, 100, 'Возможно, самым знаменитым австрийским животным является ОН, «придуманный» известным учёным в 1935 году. Похожее животное описано в романе Рэя Брэдбери «451 градус по Фаренгейту» – одновременно живой и мёртвый собакоподобный робот', 'Кот Шрёдингера', 5000),
  ('77777777-7777-7777-7777-000000200102', '77777777-7777-7777-7777-000000001006', 1, 1, 2, 200, 'Именно СТОЛЬКО различных цветов имеется на австрийском флаге', '2', 5000),
  ('77777777-7777-7777-7777-000000200103', '77777777-7777-7777-7777-000000001006', 1, 1, 3, 300, 'В 2003 году в отеле Вены была приготовлена оригинальная версия классического десерта венской кухни - торта «Захер». Новоявленный десерт назвали ТАК – в честь ЭТОГО скандально известного австрийского писателя', 'Захер-Мазох', 5000),
  ('77777777-7777-7777-7777-000000200104', '77777777-7777-7777-7777-000000001006', 1, 1, 4, 400, 'С 1770 года мелодию песни, придуманную городским музыкантом в зачумлённой Вене, вызванивали куранты Спасской Башни Московского Кремля. Как звали венского музыканта, если известно, что в песенке несколько раз повторяется его имя?', 'Августин (мелодия «Ах, мой милый Августин»)', 5000),
  ('77777777-7777-7777-7777-000000200105', '77777777-7777-7777-7777-000000001006', 1, 1, 5, 500, 'В венской НЕЙ выделяют два периода - золотую эру и серебряную, когда творили Зуппе, Штраус, Легар, Кальман. ОНА после 1920-х годов иронично называется «жестяная»', 'оперетта', 5000),
  ('77777777-7777-7777-7777-000000200106', '77777777-7777-7777-7777-000000001006', 1, 2, 1, 100, 'Впервые ЭТА награда была вручена британской гоночной команде Вануолл', 'Кубок Конструкторов', 5000),
  ('77777777-7777-7777-7777-000000200107', '77777777-7777-7777-7777-000000001006', 1, 2, 2, 200, 'В одном из дневников советский художник Сергей Калмыков писал: На НЁМ наш милейший Кузьма Сергеевич изобразил меня... Только ноги коротки от бедра. У меня в жизни длиннее', 'Красный конь', 5000),
  ('77777777-7777-7777-7777-000000200108', '77777777-7777-7777-7777-000000001006', 1, 2, 3, 300, '14 октября 2004 года ИМ стал экс-президент Кхмерской ассоциации танцев Нородом Сиамони', 'Король Камбоджи', 5000),
  ('77777777-7777-7777-7777-000000200109', '77777777-7777-7777-7777-000000001006', 1, 2, 4, 400, 'Основой британских чёрных пудингов являются именно ОНИ. Главный ингредиент этих мясных изделий очищен от фибрина', 'кровяные колбасы', 5000),
  ('77777777-7777-7777-7777-000000200110', '77777777-7777-7777-7777-000000001006', 1, 2, 5, 500, 'Настоящая фамилия ЭТОГО писателя, уроженца Флоренции, – Лоренцини.', 'Карло Коллоди', 5000),
  ('77777777-7777-7777-7777-000000200111', '77777777-7777-7777-7777-000000001006', 1, 3, 1, 100, 'Химические элементы. Дубний — Европий — ПРОПУСК — Золото — Индий', 'Железо', 5000),
  ('77777777-7777-7777-7777-000000200112', '77777777-7777-7777-7777-000000001006', 1, 3, 2, 200, 'Обладатели Кубка Стэнли. Колорадо — Лос-Анджелес — ПРОПУСК — Нью-Джерси', 'Монреаль', 5000),
  ('77777777-7777-7777-7777-000000200113', '77777777-7777-7777-7777-000000001006', 1, 3, 3, 300, 'Повести Белкина: Барышня-крестьянка, ПРОПУСК, Гробовщик', 'Выстрел', 5000),
  ('77777777-7777-7777-7777-000000200114', '77777777-7777-7777-7777-000000001006', 1, 3, 4, 400, 'Фильмы Андрея Тарковского: «Жертвоприношение» — «Зеркало» — ПРОПУСК — «Каток и скрипка»', 'Иваново детство', 5000),
  ('77777777-7777-7777-7777-000000200115', '77777777-7777-7777-7777-000000001006', 1, 3, 5, 500, 'Штаты США. Орегон — Пенсильвания — ПРОПУСК — Северная Дакота', 'Род-Айленд', 5000),
  ('77777777-7777-7777-7777-000000200116', '77777777-7777-7777-7777-000000001006', 1, 4, 1, 100, 'В июле 2022 года Магнус Карлсен, вслед за Ласкером и Фишером, стал всего лишь третьим чемпионом мира, который добровольно СДЕЛАЛ ЭТО', 'отказался от матча за мировую шахматную корону', 5000),
  ('77777777-7777-7777-7777-000000200117', '77777777-7777-7777-7777-000000001006', 1, 4, 2, 200, 'Полуголый знаменосец Американского Самоа Натан Крамптон на зимних Олимпийских играх-2022 в Пекине выступил в скелетоне, а полугодом ранее был заявлен на Олимпийских играх в Токио именно в ЭТОМ виде спорта', 'лёгкая атлетика', 5000),
  ('77777777-7777-7777-7777-000000200118', '77777777-7777-7777-7777-000000001006', 1, 4, 3, 300, 'ОНИ не стали преградой при установлении мировых рекордов нигерийкой Тоби Амусан и американкой Сидни Маклафлин на ЧМ-2022 по легкой атлетике', 'барьеры', 5000),
  ('77777777-7777-7777-7777-000000200119', '77777777-7777-7777-7777-000000001006', 1, 4, 4, 400, 'Эритреец Биниам Гирмей, несмотря на победу в рамках 10 этапа Джирод''Италия, был вынужден завершить многодневку из-за травмы глаза. Виновницей повреждения оказалась ОНА', 'пробка от шампанского', 5000),
  ('77777777-7777-7777-7777-000000200120', '77777777-7777-7777-7777-000000001006', 1, 4, 5, 500, '12 января 2022 года матч Эль Классико стал 1000-м в профессиональной карьере ЭТОГО футболиста - уже экс-защитника Барселоны', 'Дани Алвес', 5000),
  ('77777777-7777-7777-7777-000000200121', '77777777-7777-7777-7777-000000001007', 1, 1, 1, 100, 'ЭТИМ словом в генетике называют изменение в последовательности ДНК или структуре гена, произошедшее в результате, к примеру, замен оснований в ДНК', 'мутация', 5000),
  ('77777777-7777-7777-7777-000000200122', '77777777-7777-7777-7777-000000001007', 1, 1, 2, 200, 'Если трансляция - это процесс синтеза белка с помощью информации с матричной РНК, то ОНА представляет собой процесса перевода в РНК генетической информации, заложенной в ДНК', 'транскрипция', 5000),
  ('77777777-7777-7777-7777-000000200123', '77777777-7777-7777-7777-000000001007', 1, 1, 3, 300, 'ЭТИ альтернативные вариации одного гена могут быть доминантными или рецессивными. В числе прочего, они могут образоваться в результате мутации в последовательности ДНК', 'аллели', 5000),
  ('77777777-7777-7777-7777-000000200124', '77777777-7777-7777-7777-000000001007', 1, 1, 4, 400, 'ЭТОТ Джеймс стал первым человеком, чей геном был секвенирован', 'Уотсон', 5000),
  ('77777777-7777-7777-7777-000000200125', '77777777-7777-7777-7777-000000001007', 1, 1, 5, 500, 'иРНК - информационная, тРНК - транспортная, а вот мтРНК–именно ТАКАЯ', 'митохондриальная', 5000),
  ('77777777-7777-7777-7777-000000200126', '77777777-7777-7777-7777-000000001007', 1, 2, 1, 100, 'Уступ в одном из кратеров Меркурия назван ТАК в честь знаменитой подводной лодки Жюля Верна', 'Наутилус', 5000),
  ('77777777-7777-7777-7777-000000200127', '77777777-7777-7777-7777-000000001007', 1, 2, 2, 200, 'Несмотря на то, что Меркурий ближе других планет находится к Солнцу, его разреженная атмосфера не может удержать тепло. А самой горячей является ЭТА планета, чья плотная атмосфера прекрасно справляется с этой задачей', 'Венера', 5000),
  ('77777777-7777-7777-7777-000000200128', '77777777-7777-7777-7777-000000001007', 1, 2, 3, 300, 'ЭТОТ металл считали основой всех металлов, близким к золоту, и поэтому назвали меркурием (Mercurius), по имени ближайшей к Солнцу (то есть золоту) планеты', 'ртуть', 5000),
  ('77777777-7777-7777-7777-000000200129', '77777777-7777-7777-7777-000000001007', 1, 2, 4, 400, 'Геологи Горной школы Колорадо предположили, что около 4 млн лет назад врезавшиеся в Меркурий астероиды попали в графит, покрывавший большую часть планеты, превратив графит в ЭТО', 'алмазы', 5000),
  ('77777777-7777-7777-7777-000000200130', '77777777-7777-7777-7777-000000001007', 1, 2, 5, 500, 'Оптическое явление на Меркурии, когда Солнце останавливается на небе и движется в противоположную сторону, получило название в честь ЭТОГО библейского персонажа, остановившего на небе Солнце и Луну, чтобы противник не смог отступить, воспользовавшись вечерним и ночным мраком', 'Иисус Навин', 5000),
  ('77777777-7777-7777-7777-000000200131', '77777777-7777-7777-7777-000000001007', 1, 3, 1, 100, 'Впервые ОНА была упомянута в трактате XVIII века как валенсийский рис', 'пАЭлья', 5000),
  ('77777777-7777-7777-7777-000000200132', '77777777-7777-7777-7777-000000001007', 1, 3, 2, 200, 'Первым автомобилем представительского класса за 70-летнюю историю концерна стала именноЭТА модель Фольксвагена', 'фАЭтон', 5000),
  ('77777777-7777-7777-7777-000000200133', '77777777-7777-7777-7777-000000001007', 1, 3, 3, 300, 'Среди основателей ЭТОГО Братства значились и родные братья — студенты Королевской Академии художеств Данте Габриэль Россетти и Уильям Россетти', 'прерафАЭлиты', 5000),
  ('77777777-7777-7777-7777-000000200134', '77777777-7777-7777-7777-000000001007', 1, 3, 4, 400, 'ЭТА звёздчатая форма икосаэдра названа в честь млекопитающего из отряда яйцекладущих', 'ехиднАЭдр', 5000),
  ('77777777-7777-7777-7777-000000200135', '77777777-7777-7777-7777-000000001007', 1, 3, 5, 500, 'Весной 2002 года — через 82 года после своего основания — ЭТОТ футбольный клуб впервые стал чемпионом Венгрии, а спустя 2,5 месяца обыграл Манчестер Юнайтед сэра Алекса Фергюсона в квалификации Лиги Чемпионов', 'ЗалАЭгерсег', 5000),
  ('77777777-7777-7777-7777-000000200136', '77777777-7777-7777-7777-000000001007', 1, 4, 1, 100, '99-й день календарного года выпадает на ЭТОТ месяц', 'апрель', 5000),
  ('77777777-7777-7777-7777-000000200137', '77777777-7777-7777-7777-000000001007', 1, 4, 2, 200, 'Число 99 неоднократно упомянуто в знаменитом стихотворении «Сотый» ЭТОГО первого из английских лауреатов Нобелевской премии по литературе', 'Киплинг', 5000),
  ('77777777-7777-7777-7777-000000200138', '77777777-7777-7777-7777-000000001007', 1, 4, 3, 300, 'Последним европейским клубом в карьере ЭТОГО легендарного форварда стал Милан, где бразилец играл под 99-м номером, т.к. любимая девятка была занята Филиппо Индзаги', 'Роналдо', 5000),
  ('77777777-7777-7777-7777-000000200139', '77777777-7777-7777-7777-000000001007', 1, 4, 4, 400, 'В песне «99 Luftballons» [нойн унд нойнцихь люфтбаллонс] немецкой группы Nena, популярной в 1980-е, поётся о 99 воздушных шариках, которые были ошибочно приняты за ЭТО и уничтожены. Ответьте аббревиатурой', 'НЛО', 5000),
  ('77777777-7777-7777-7777-000000200140', '77777777-7777-7777-7777-000000001007', 1, 4, 5, 500, 'ЭТО приспособление служит ответом на калмыцкую загадку: У очень маленькой вещи 99 глаз', 'напёрсток', 5000),
  ('77777777-7777-7777-7777-000000200141', '77777777-7777-7777-7777-000000001008', 1, 1, 1, 100, 'В различных переводах ОНО начинается со слов «Не прилично ли будет..., Не пристало ли нам..., Не лепо ли ны...» и ряда иных вариантов', 'Слово о полку Игореве', 5000),
  ('77777777-7777-7777-7777-000000200142', '77777777-7777-7777-7777-000000001008', 1, 1, 2, 200, 'Наибольшего счёта за первый ход в ЭТОЙ игре добился Сэм Кантимати, который выложил слово BEZIQUE (безик), оценённое в 124 очка', 'Скраббл (скрэббл/эрудит)', 5000),
  ('77777777-7777-7777-7777-000000200143', '77777777-7777-7777-7777-000000001008', 1, 1, 3, 300, 'Название ЭТОГО музыкального произведения Средневековья и Ренессанса пошло от старофранцузского «mot», означающего «слово»', 'мотет', 5000),
  ('77777777-7777-7777-7777-000000200144', '77777777-7777-7777-7777-000000001008', 1, 1, 4, 400, 'Единственным лауреатом венецианского Золотого льва от ЭТОЙ страны является фильм Карла Теодора Дрейера «Слово», представляющий собой экранизацию пьесы Кая Мунка «В начале было Слово»', 'Дания', 5000),
  ('77777777-7777-7777-7777-000000200145', '77777777-7777-7777-7777-000000001008', 1, 1, 5, 500, '«А 17-го числа декабря месяца явилось снегу велика…», – так Кар-Карыч начал историю смешариков в серии «В начале было слово». Позже подключились и другие, а ЕГО для участия в общем деле пришлось вывести из фазы глубокого сна', 'Копатыч', 5000),
  ('77777777-7777-7777-7777-000000200146', '77777777-7777-7777-7777-000000001008', 1, 2, 1, 100, 'Табор ― Кветов ― Чижова ― Радомышль ― Писек ― Будейовицы', 'Похождения бравого солдата Швейка (Ярослав Гашек)', 5000),
  ('77777777-7777-7777-7777-000000200147', '77777777-7777-7777-7777-000000001008', 1, 2, 2, 200, 'Кингстон ― Хэмптон-Корт ― Стэйнс ― Марло ― Рединг ― Оксфорд', 'Трое в лодке, не считая собаки (Джером Клапка Джером)', 5000),
  ('77777777-7777-7777-7777-000000200148', '77777777-7777-7777-7777-000000001008', 1, 2, 3, 300, 'Балтийское море ― Кале ― Суэц ― Антарктида ― Белен ― мыс Горн ― Канада ― Петропавловск-Камчатский', 'Приключения капитана Врунгеля (Андрей Некрасов)', 5000),
  ('77777777-7777-7777-7777-000000200149', '77777777-7777-7777-7777-000000001008', 1, 2, 4, 400, 'Лев ― лисица ― морж ― слон ― журавль ― носорог ― кенгуру ― медведь ― крокодил', 'Где обедал, воробей? (стихотворение Самуила Маршака)', 5000),
  ('77777777-7777-7777-7777-000000200150', '77777777-7777-7777-7777-000000001008', 1, 2, 5, 500, 'Португалия ― Испания ― Албания ― Греция ― Британия ― Бельгии ― Германия ― Швейцария ― Италия', 'Паломничество Чайлд-Гарольда (Джордж Байрон)', 5000),
  ('77777777-7777-7777-7777-000000200151', '77777777-7777-7777-7777-000000001008', 1, 3, 1, 100, 'На знаменитом полотне Виктора Васнецова ЭТОТ богатырь изображён по центру относительно двух других', 'Илья Муромец', 5000),
  ('77777777-7777-7777-7777-000000200152', '77777777-7777-7777-7777-000000001008', 1, 3, 2, 200, 'ЭТОТ роман Теодора Драйзера из цикла «Трилогия желания» был издан уже после смерти писателя', 'Стоик', 5000),
  ('77777777-7777-7777-7777-000000200153', '77777777-7777-7777-7777-000000001008', 1, 3, 3, 300, 'Однажды ЭТОТ участник легендарного трио великих теноров был номинирован на «Золотую малину» в категориях «Худший актёр» и «Худшая новая звезда»', 'Паваротти', 5000),
  ('77777777-7777-7777-7777-000000200154', '77777777-7777-7777-7777-000000001008', 1, 3, 4, 400, 'Мировой рекордсменкой в метании ЭТОГО легкоатлетического снаряда является полька Анита Влодарчик', 'молот', 5000),
  ('77777777-7777-7777-7777-000000200155', '77777777-7777-7777-7777-000000001008', 1, 3, 5, 500, 'Лишь трое русских царей носили имя Фёдор. Укажите ОТЧЕСТВО того из них, чей срок пребывания на престоле оказался наименьшим', 'Борисович', 5000),
  ('77777777-7777-7777-7777-000000200156', '77777777-7777-7777-7777-000000001008', 1, 4, 1, 100, 'ЭТИМ материалом Гудвин наполнил красивое шёлковое сердце для Железного Дровосека', 'опилки', 5000),
  ('77777777-7777-7777-7777-000000200157', '77777777-7777-7777-7777-000000001008', 1, 4, 2, 200, 'На альбоме «25 кадр» ЭТОЙ группы можно найти и прослушать песню «Моё сердце»', 'Сплин', 5000),
  ('77777777-7777-7777-7777-000000200158', '77777777-7777-7777-7777-000000001008', 1, 4, 3, 300, 'Правая половина сердца получает венозную кровь от всего тела и направляет её в ЭТОТ орган', 'лёгкие', 5000),
  ('77777777-7777-7777-7777-000000200159', '77777777-7777-7777-7777-000000001008', 1, 4, 4, 400, 'Согласно утверждённому Международной ассоциацией ювелиров списку камней-талисманов, ЭТОТ камень охраняет супружеское счастье и верность, а также защищает от колдовства', 'сердолик', 5000),
  ('77777777-7777-7777-7777-000000200160', '77777777-7777-7777-7777-000000001008', 1, 4, 5, 500, 'ТАК называется повесть Достоевского о студенте, который выполнял заказ по переписыванию тетрадных рукописей, а когда понял, что к сроку ему не уложиться, сошёл с ума', 'Слабое сердце', 5000)
ON CONFLICT (id) DO NOTHING;

